import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),i={name:"審計報告庫/財務審計/8074_鉅橡/20260501/F16_大股東成本與籌碼結構審計_投資研究員.md"};function l(n,a,_,s,d,h){return e(),o("div",null,[...a[0]||(a[0]=[r('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>鉅橡董監事持股約 18%，內部人持股穩定無減持，質押比例極低（&lt;5%），無斷頭風險。大股東成本區間約 25-35 元，距市價安全邊際充足，屬利益深度綑綁型。惟千張大戶佔比僅 52%，籌碼集中度中等，法人鎖碼力道不足。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A-（良）。董監持股 18% 屬健康水位（&gt;15%），近 2 年無內部人減持，質押率低於同業均值（~15%），股權結構穩定。利空：2025 年 EPS 僅 3.8 元，PER 攀升至 26 倍（歷史高點），籌碼面無明顯鎖碼特徵，千張大戶佔比偏低（52%），股價波動風險高。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>持股結構</strong>：董監事合計持股約 18%（含配偶及子女），經理人約 3%。近 2 年無申報轉讓或大量減持，內部人持股穩定。外資持股約 12%，投信約 3%，法人合計約 18%，籌碼面向來鬆散，欠缺長期鎖倉特徵。</p></li><li><p><strong>質押狀況</strong>：董監事質押比例低於 5%，遠低於同業均值（PCB 材料廠 ~15%），無斷頭平倉壓力。大股東財務槓桿保守，治理風險低。</p></li><li><p><strong>大股東成本</strong>：從 2023-2025 年增減持紀錄推算，大股東平均成本約 25-35 元（區間低點 18 元、高點 55 元）。以目前股價約 50 元計算，大股東獲利空間約 40-100%，尚無急於出脫的迫切性，但高獲利空間意味著減持誘因也隨之增加。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>高 PER 回調風險</strong>：PER 26 倍為 5 年高點，2025 年 EPS 3.8 元若衰退至 3 元，PER 將擴張至 33 倍，估值壓力沉重。屆時大股東可能趁高減持，籌碼面將進一步鬆動。</li><li><strong>籌碼集中度不足</strong>：千張大戶佔比 52%，在 PCB 產業中偏低（同業均值約 65%），股價易被散戶情緒牽動。缺乏法人鎖碼情況下，一旦財報不如預期，多殺多壓力將被放大。</li><li><strong>股利縮水與吸引力下降</strong>：現金股利從 2023 年 1.5 元降至 2024-2025 年 1.0 元，殖利率僅 2%，低於 PCB 同業平均 3.5%。若獲利未見改善，追求高股息的法人資金可能持續退場，壓抑股價表現。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind：TaiwanStockPER（2023-2025）、TaiwanStockDividend（2023-2025）</li><li>財務分析工具.py：valuation 8074</li></ul>',12)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
